// NewMediaJSONClient creates a JSON client that implements the Media interface.
// It communicates using JSON and can be configured with a custom HTTPClient.
func NewMediaJSONClient(baseURL string, client HTTPClient, opts ...twirp.ClientOption) Media {
	if c, ok := client.(*http.Client); ok {
		client = withoutRedirects(c)
	}

	clientOpts := twirp.ClientOptions{}
	for _, o := range opts {
		o(&clientOpts)
	}

	// Using ReadOpt allows backwards and forwards compatibility with new options in the future
	literalURLs := false
	_ = clientOpts.ReadOpt("literalURLs", &literalURLs)
	var pathPrefix string
	if ok := clientOpts.ReadOpt("pathPrefix", &pathPrefix); !ok {
		pathPrefix = "/twirp" // default prefix
	}

	// Build method URLs: <baseURL>[<prefix>]/<package>.<Service>/<Method>
	serviceURL := sanitizeBaseURL(baseURL)
	serviceURL += baseServicePath(pathPrefix, "ttab.ntb", "Media")
	urls := [3]string{
		serviceURL + "Search",
		serviceURL + "GetItem",
		serviceURL + "GetSortFields",
	}

	return &mediaJSONClient{
		client:      client,
		urls:        urls,
		interceptor: twirp.ChainInterceptors(clientOpts.Interceptors...),
		opts:        clientOpts,
	}
}

